# Generated by anthropic (claude-sonnet-4-5)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

properties([
    parameters([
        string(name: 'ARTIFACT_URL', defaultValue: '', description: 'URL to download the artifact from (S3, Artifactory, HTTP)'),
        string(name: 'ARTIFACT_NAME', defaultValue: 'application.jar', description: 'Name to save the artifact as'),
        choice(name: 'ENVIRONMENT', choices: ['staging', 'production'], description: 'Target environment'),
        string(name: 'DEPLOYMENT_SERVERS', defaultValue: '', description: 'Comma-separated list of servers to deploy to'),
        string(name: 'DEPLOYMENT_PATH', defaultValue: '/opt/application', description: 'Path on target servers to deploy artifact'),
        string(name: 'SERVICE_NAME', defaultValue: 'application', description: 'Service name to restart after deployment'),
        booleanParam(name: 'BACKUP_EXISTING', defaultValue: true, description: 'Backup existing artifact before deployment'),
        booleanParam(name: 'RESTART_SERVICE', defaultValue: true, description: 'Restart service after deployment'),
        string(name: 'HEALTH_CHECK_URL', defaultValue: '', description: 'URL to check application health after deployment'),
        string(name: 'CREDENTIALS_ID', defaultValue: '', description: 'Credentials ID for authenticated downloads (optional)'),
        string(name: 'SSH_CREDENTIALS_ID', defaultValue: 'ssh-deploy-key', description: 'SSH credentials for server access'),
        string(name: 'CHECKSUM_URL', defaultValue: '', description: 'URL to checksum file for verification (optional)'),
        choice(name: 'CHECKSUM_TYPE', choices: ['sha256', 'sha1', 'md5'], description: 'Checksum algorithm'),
        text(name: 'PRE_DEPLOY_COMMANDS', defaultValue: '', description: 'Commands to run before deployment (one per line)'),
        text(name: 'POST_DEPLOY_COMMANDS', defaultValue: '', description: 'Commands to run after deployment (one per line)'),
        string(name: 'ROLLBACK_VERSION', defaultValue: '', description: 'Version to rollback to if deployment fails (optional)'),
        string(name: 'DEPLOYMENT_USER', defaultValue: 'deploy', description: 'User to run deployment as on target servers'),
        string(name: 'FILE_PERMISSIONS', defaultValue: '755', description: 'File permissions for deployed artifact'),
        booleanParam(name: 'PARALLEL_DEPLOYMENT', defaultValue: false, description: 'Deploy to all servers in parallel'),
        string(name: 'DEPLOYMENT_TIMEOUT', defaultValue: '300', description: 'Deployment timeout in seconds')
    ])
])

pipeline {
    agent any
    
    environment {
        WORKSPACE_ARTIFACTS = "${WORKSPACE}/artifacts"
        DEPLOYMENT_TIMESTAMP = sh(script: "date +%Y%m%d_%H%M%S", returnStdout: true).trim()
    }
    
    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    if (!params.ARTIFACT_URL) {
                        error("ARTIFACT_URL parameter is required")
                    }
                    if (!params.DEPLOYMENT_SERVERS) {
                        error("DEPLOYMENT_SERVERS parameter is required")
                    }
                    
                    echo "Artifact URL: ${params.ARTIFACT_URL}"
                    echo "Target Environment: ${params.ENVIRONMENT}"
                    echo "Deployment Servers: ${params.DEPLOYMENT_SERVERS}"
                    echo "Deployment Path: ${params.DEPLOYMENT_PATH}"
                }
            }
        }
        
        stage('Prepare Workspace') {
            steps {
                script {
                    sh "mkdir -p ${WORKSPACE_ARTIFACTS}"
                    sh "rm -rf ${WORKSPACE_ARTIFACTS}/*"
                }
            }
        }
        
        stage('Download Artifact') {
            steps {
                script {
                    def artifactPath = "${WORKSPACE_ARTIFACTS}/${params.ARTIFACT_NAME}"
                    
                    echo "Downloading artifact from: ${params.ARTIFACT_URL}"
                    
                    if (params.CREDENTIALS_ID) {
                        withCredentials([usernamePassword(credentialsId: params.CREDENTIALS_ID, 
                                                         usernameVariable: 'USERNAME', 
                                                         passwordVariable: 'PASSWORD')]) {
                            if (params.ARTIFACT_URL.startsWith('s3://')) {
                                sh """
                                    aws s3 cp ${params.ARTIFACT_URL} ${artifactPath}
                                """
                            } else {
                                sh """
                                    curl -u ${USERNAME}:${PASSWORD} -L -o ${artifactPath} ${params.ARTIFACT_URL}
                                """
                            }
                        }
                    } else {
                        if (params.ARTIFACT_URL.startsWith('s3://')) {
                            sh """
                                aws s3 cp ${params.ARTIFACT_URL} ${artifactPath}
                            """
                        } else {
                            sh """
                                curl -L -o ${artifactPath} ${params.ARTIFACT_URL}
                            """
                        }
                    }
                    
                    sh "ls -lh ${artifactPath}"
                    
                    if (!fileExists(artifactPath)) {
                        error("Failed to download artifact from ${params.ARTIFACT_URL}")
                    }
                }
            }
        }
        
        stage('Verify Checksum') {
            when {
                expression { params.CHECKSUM_URL != '' }
            }
            steps {
                script {
                    def artifactPath = "${WORKSPACE_ARTIFACTS}/${params.ARTIFACT_NAME}"
                    def checksumPath = "${WORKSPACE_ARTIFACTS}/checksum.txt"
                    
                    echo "Downloading checksum from: ${params.CHECKSUM_URL}"
                    
                    if (params.CREDENTIALS_ID) {
                        withCredentials([usernamePassword(credentialsId: params.CREDENTIALS_ID, 
                                                         usernameVariable: 'USERNAME', 
                                                         passwordVariable: 'PASSWORD')]) {
                            sh """
                                curl -u ${USERNAME}:${PASSWORD} -L -o ${checksumPath} ${params.CHECKSUM_URL}
                            """
                        }
                    } else {
                        sh """
                            curl -L -o ${checksumPath} ${params.CHECKSUM_URL}
                        """
                    }
                    
                    def expectedChecksum = sh(script: "cat ${checksumPath} | awk '{print \$1}'", returnStdout: true).trim()
                    def actualChecksum = sh(script: "${params.CHECKSUM_TYPE}sum ${artifactPath} | awk '{print \$1}'", returnStdout: true).trim()
                    
                    echo "Expected ${params.CHECKSUM_TYPE}: ${expectedChecksum}"
                    echo "Actual ${params.CHECKSUM_TYPE}: ${actualChecksum}"
                    
                    if (expectedChecksum != actualChecksum) {
                        error("Checksum verification failed! Expected: ${expectedChecksum}, Got: ${actualChecksum}")
                    }
                    
                    echo "Checksum verification successful"
                }
            }
        }
        
        stage('Deploy to Servers') {
            steps {
                script {
                    def servers = params.DEPLOYMENT_SERVERS.split(',').collect { it.trim() }
                    def artifactPath = "${WORKSPACE_ARTIFACTS}/${params.ARTIFACT_NAME}"
                    
                    if (params.PARALLEL_DEPLOYMENT) {
                        def deploymentSteps = [:]
                        
                        servers.each { server ->
                            deploymentSteps[server] = {
                                deployToServer(server, artifactPath)
                            }
                        }
                        
                        parallel deploymentSteps
                    } else {
                        servers.each { server ->
                            deployToServer(server, artifactPath)
                        }
                    }
                }
            }
        }
        
        stage('Health Check') {
            when {
                expression { params.HEALTH_CHECK_URL != '' }
            }
            steps {
                script {
                    def servers = params.DEPLOYMENT_SERVERS.split(',').collect { it.trim() }
                    
                    echo "Waiting 10 seconds for services to start..."
                    sleep(10)
                    
                    servers.each { server ->
                        def healthUrl = params.HEALTH_CHECK_URL.replace('SERVER_PLACEHOLDER', server)
                        
                        echo "Checking health for ${server}: ${healthUrl}"
                        
                        def maxRetries = 5
                        def retryDelay = 10
                        def healthy = false
                        
                        for (int i = 0; i < maxRetries; i++) {
                            try {
                                def response = sh(script: "curl -s -o /dev/null -w '%{http_code}' ${healthUrl}", returnStdout: true).trim()
                                
                                if (response == '200') {
                                    echo "Health check passed for ${server}"
                                    healthy = true
                                    break
                                } else {
                                    echo "Health check returned ${response} for ${server}, retrying..."
                                }
                            } catch (Exception e) {
                                echo "Health check failed for ${server}: ${e.message}, retrying..."
                            }
                            
                            if (i < maxRetries - 1) {
                                sleep(retryDelay)
                            }
                        }
                        
                        if (!healthy) {
                            error("Health check failed for ${server} after ${maxRetries} attempts")
                        }
                    }
                }
            }
        }
    }
    
    post {
        success {
            script {
                echo "Deployment completed successfully!"
                echo "Environment: ${params.ENVIRONMENT}"
                echo "Artifact: ${params.ARTIFACT_NAME}"
                echo "Servers: ${params.DEPLOYMENT_SERVERS}"
            }
        }
        failure {
            script {
                echo "Deployment failed!"
                
                if (params.ROLLBACK_VERSION) {
                    echo "Rollback version specified: ${params.ROLLBACK_VERSION}"
                    echo "Manual rollback may be required"
                }
            }
        }
        always {
            script {
                sh "rm -rf ${WORKSPACE_ARTIFACTS}"
            }
        }
    }
}

def deployToServer(String server, String artifactPath) {
    echo "Deploying to server: ${server}"
    
    sshagent(credentials: [params.SSH_CREDENTIALS_ID]) {
        timeout(time: params.DEPLOYMENT_TIMEOUT.toInteger(), unit: 'SECONDS') {
            if (params.BACKUP_EXISTING) {
                echo "Backing up existing artifact on ${server}"
                sh """
                    ssh -o StrictHostKeyChecking=no ${params.DEPLOYMENT_USER}@${server} '
                        if [ -f ${params.DEPLOYMENT_PATH}/${params.ARTIFACT_NAME} ]; then
                            cp ${params.DEPLOYMENT_PATH}/${params.ARTIFACT_NAME} ${params.DEPLOYMENT_PATH}/${params.ARTIFACT_NAME}.backup.${DEPLOYMENT_TIMESTAMP}
                            echo "Backup created: ${params.ARTIFACT_NAME}.backup.${DEPLOYMENT_TIMESTAMP}"
                        fi
                    '
                """
            }
            
            if (params.PRE_DEPLOY_COMMANDS) {
                echo "Executing pre-deployment commands on ${server}"
                def preCommands = params.PRE_DEPLOY_COMMANDS.split('\n').findAll { it.trim() }
                preCommands.each { cmd ->
                    if (cmd.trim()) {
                        sh """
                            ssh -o StrictHostKeyChecking=no ${params.DEPLOYMENT_USER}@${server} '${cmd.trim()}'
                        """
                    }
                }
            }
            
            if (params.RESTART_SERVICE) {
                echo "Stopping service ${params.SERVICE_NAME} on ${server}"
                sh """
                    ssh -o StrictHostKeyChecking=no ${params.DEPLOYMENT_USER}@${server} '
                        sudo systemctl stop ${params.SERVICE_NAME} || true
                    '
                """
            }
            
            echo "Copying artifact to ${server}"
            sh """
                ssh -o StrictHostKeyChecking=no ${params.DEPLOYMENT_USER}@${server} '
                    mkdir -p ${params.DEPLOYMENT_PATH}
                '
                scp -o StrictHostKeyChecking=no ${artifactPath} ${params.DEPLOYMENT_USER}@${server}:${params.DEPLOYMENT_PATH}/${params.ARTIFACT_NAME}
            """
            
            echo "Setting permissions on ${server}"
            sh """
                ssh -o StrictHostKeyChecking=no ${params.DEPLOYMENT_USER}@${server} '
                    chmod ${params.FILE_PERMISSIONS} ${params.DEPLOYMENT_PATH}/${params.ARTIFACT_NAME}
                '
            """
            
            if (params.POST_DEPLOY_COMMANDS) {
                echo "Executing post-deployment commands on ${server}"
                def postCommands = params.POST_DEPLOY_COMMANDS.split('\n').findAll { it.trim() }
                postCommands.each { cmd ->
                    if (cmd.trim()) {
                        sh """
                            ssh -o StrictHostKeyChecking=no ${params.DEPLOYMENT_USER}@${server} '${cmd.trim()}'
                        """
                    }
                }
            }
            
            if (params.RESTART_SERVICE) {
                echo "Starting service ${params.SERVICE_NAME} on ${server}"
                sh """
                    ssh -o StrictHostKeyChecking=no ${params.DEPLOYMENT_USER}@${server} '
                        sudo systemctl start ${params.SERVICE_NAME}
                        sudo systemctl status ${params.SERVICE_NAME}
                    '
                """
            }
            
            echo "Deployment to ${server} completed successfully"
        }
    }
}